import { mergeProps, Show, type Component } from 'solid-js';
import type { CollapseProps } from './collapse.types';
import { cn } from '@/utils/cn';
import { cva, type VariantProps } from 'class-variance-authority';
import { getColor } from '@/utils/helper';

const variants = cva('', {
  variants: {
    iconType: {
      plus: 'collapse-plus',
      arrow: 'collapse-arrow',
    },
    iconPosition: {
      start: 'after:start-5 after:end-auto pe-4 ps-12',
      end: '',
    },
    forceStatus: {
      open: 'collapse-open',
      close: 'collapse-close',
    },
  },
});
export type CollapseVariantsProps = VariantProps<typeof variants>;

export const Collapse: Component<CollapseProps> = p => {
  p = mergeProps(
    {
      icon: {
        type: 'arrow',
        postion: 'end',
      },
      color: 'transparent',
    } as CollapseProps,
    p,
  );

  return (
    <>
      <div
        class={cn(
          'collapse border',
          variants({ iconType: p.icon?.type, forceStatus: p.force }),
          getColor(p.color, 'bg-base-100 border-base-300'),
          p.color && p.color !== 'transparent' && 'sui-collapse',
          p.class?.root,
        )}
      >
        <Show when={!p.force}>
          <input
            type="checkbox"
            {...(p.onOpen || p.onClose
              ? {
                  onChange: e => {
                    const checked = e.currentTarget.checked;
                    checked ? p.onOpen?.() : p.onClose?.();
                  },
                }
              : {})}
            {...(p.id && { id: p.id })}
          />
        </Show>
        <div
          class={cn(
            'collapse-title font-semibold',
            variants({ iconPosition: p.icon?.postion }),
            p.class?.title,
            p.force && (p.onOpen || p.onClose) ? 'cursor-pointer' : '',
          )}
          {...(p.force && (p.onOpen || p.onClose)
            ? {
                onClick: () => {
                  p.force === 'open' ? p.onClose?.() : p.onOpen?.();
                },
              }
            : {})}
        >
          {p.title}
        </div>
        <div class={cn('collapse-content text-sm', p.class?.content)}>{p.content as Element}</div>
      </div>
    </>
  );
};
